use codama_nodes::Docs;
use codama_nodes::Number;
use heck::ToShoutySnakeCase;
use heck::ToSnakeCase;
use heck::ToUpperCamelCase;

use crate::error::RenderError;
use crate::error::Result;

pub(crate) const GENERATED_HEADER: &str = r"//! This code was AUTOGENERATED by `pina_codama_renderer`.
//! Please DO NOT EDIT THIS FILE directly.
//! Regenerate it from Codama IDLs instead.
#![allow(
	clippy::doc_lazy_continuation,
	clippy::empty_line_after_doc_comments,
	clippy::new_without_default,
	clippy::too_many_arguments
)]
";

pub(crate) fn page(body: &str) -> String {
	format!("{GENERATED_HEADER}\n{body}\n")
}

pub(crate) fn pascal(value: &str) -> String {
	value.to_upper_camel_case()
}

pub(crate) fn snake(value: &str) -> String {
	value.to_snake_case()
}

pub(crate) fn shouty(value: &str) -> String {
	value.to_shouty_snake_case()
}

pub(crate) fn program_id_const_name(program_name: &str) -> String {
	shouty(program_name) + "_ID"
}

pub(crate) fn escape_rust_str(value: &str) -> String {
	value.replace('\\', "\\\\").replace('"', "\\\"")
}

pub(crate) fn render_docs(docs: &Docs, indent_level: usize) -> Vec<String> {
	let indent = "\t".repeat(indent_level);
	docs.iter()
		.map(|line| format!("{indent}/// {line}"))
		.collect()
}

pub(crate) fn cast_unsigned(value: &Number, max: u128, context: &str) -> Result<u128> {
	let parsed = match value {
		Number::UnsignedInteger(value) => u128::from(*value),
		Number::SignedInteger(value) => {
			u128::try_from(*value).map_err(|_| {
				RenderError::UnsupportedValue {
					context: context.to_string(),
					kind: "numberValueNode",
					reason: "negative number cannot be cast to unsigned value".to_string(),
				}
			})?
		}
		Number::Float(_) => {
			return Err(RenderError::UnsupportedValue {
				context: context.to_string(),
				kind: "numberValueNode",
				reason: "float cannot be cast to integer".to_string(),
			});
		}
	};
	if parsed > max {
		return Err(RenderError::UnsupportedValue {
			context: context.to_string(),
			kind: "numberValueNode",
			reason: format!("value `{parsed}` exceeds max `{max}`"),
		});
	}
	Ok(parsed)
}

pub(crate) fn cast_signed(value: &Number, min: i128, max: i128, context: &str) -> Result<i128> {
	let parsed = match value {
		Number::UnsignedInteger(value) => i128::from(*value),
		Number::SignedInteger(value) => i128::from(*value),
		Number::Float(_) => {
			return Err(RenderError::UnsupportedValue {
				context: context.to_string(),
				kind: "numberValueNode",
				reason: "float cannot be cast to integer".to_string(),
			});
		}
	};
	if parsed < min || parsed > max {
		return Err(RenderError::UnsupportedValue {
			context: context.to_string(),
			kind: "numberValueNode",
			reason: format!("value `{parsed}` is out of range [{min}, {max}]"),
		});
	}
	Ok(parsed)
}
